# === bracket_checker.py ===
def is_balanced(s: str) -> bool:
    """判断字符串中的小括号是否匹配。

    只处理 '(' 和 ')'，忽略其他字符。

    Args:
        s: 输入字符串

    Returns:
        括号匹配返回 True，否则返回 False
    """
    count = 0
    for ch in s:
        if ch == '(':
            count += 1
        elif ch == ')':
            count -= 1
            if count < 0:
                return False
    return count == 0


def is_balanced_extended(s: str) -> bool:
    """判断字符串中的小括号、中括号、大括号是否匹配。

    支持的括号对：() [] {}
    必须正确嵌套。

    Args:
        s: 输入字符串

    Returns:
        括号匹配返回 True，否则返回 False
    """
    pairs = {')': '(', ']': '[', '}': '{'}
    stack = []

    for ch in s:
        if ch in '([{':
            stack.append(ch)
        elif ch in ')]}':
            if not stack or stack[-1] != pairs[ch]:
                return False
            stack.pop()

    return len(stack) == 0


class BracketChecker:
    """括号匹配检查器，提供 is_balanced 和 is_balanced_extended 两个类方法。"""

    @staticmethod
    def is_balanced(s: str) -> bool:
        """判断字符串中的小括号是否匹配。

        Args:
            s: 输入字符串

        Returns:
            括号匹配返回 True，否则返回 False
        """
        return is_balanced(s)

    @staticmethod
    def is_balanced_extended(s: str) -> bool:
        """判断字符串中的小括号、中括号、大括号是否匹配。

        Args:
            s: 输入字符串

        Returns:
            括号匹配返回 True，否则返回 False
        """
        return is_balanced_extended(s)
